export class SearchComponent {
  query = '';
  results = [];
  timerId = null;
  searchService;

  constructor(searchService) {
    this.searchService = searchService;
  }

  onInput(term) {
    this.query = term;
    if (this.timerId !== null) {
      clearTimeout(this.timerId);
    }
    this.timerId = setTimeout(() => {
      this.results = this.searchService.search(term);
      this.timerId = null;
    }, 300);
  }
}

