export class MasterDetailComponent {
  selectedId = null;

  items = [
    { id: 1, name: 'Relay Station Alpha' },
    { id: 2, name: 'Deep Probe Beta' },
    { id: 3, name: 'Anchor Node Gamma' },
  ];

  select(id) {
    this.selectedId = id;
  }

  get selectedItem() {
    return this.items.find(i => i.id === this.selectedId) ?? null;
  }

  get detailLabel() {
    return this.selectedItem ? 'Viewing: ' + this.selectedItem.name : 'Select an item';
  }
}
